<?php
namespace App\Domain\Shops;use App\Domain\Shops\Exceptions\ShopSaleUnavailableException;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\Shop;use App\Models\Zone;use Carbon\CarbonImmutable;
final class ShopAccessService{private $availability;public function __construct(ShopAvailabilityService $a){$this->availability=$a;}public function authorize(Shop $shop,Character $character,$zoneId,CarbonImmutable $now){$shop->loadMissing(['npc','locations']);if(!$this->availability->isShopVisible($shop,$now))throw new ShopSaleUnavailableException();if($shop->locations->isEmpty())return null;if(!$zoneId)throw new ShopSaleUnavailableException();$location=$shop->locations->first(function($l)use($zoneId){return$l->locatable_type===ShopLocationType::ZONE&&(int)$l->locatable_id===(int)$zoneId&&$l->status===CatalogStatus::ACTIVE;});if(!$location||!Zone::whereKey($zoneId)->where('status',CatalogStatus::ACTIVE)->exists())throw new ShopSaleUnavailableException();return(int)$zoneId;}}
